<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;use Illuminate\Database\Eloquent\Relations\BelongsTo;use Illuminate\Database\Eloquent\Relations\HasMany;use Illuminate\Database\Eloquent\Relations\BelongsToMany;
class Umkm extends Model { use SoftDeletes; protected $fillable=['umkm_code','business_name','status_data','quality_status','established_date','notes','created_by','updated_by','deleted_by']; public function owners(): HasMany { return $this->hasMany(UmkmOwner::class); } public function userLinks(): HasMany { return $this->hasMany(UmkmUserLink::class); } public function users(): BelongsToMany { return $this->belongsToMany(User::class, 'umkm_user_links')->withPivot(['relationship_type','is_primary'])->withTimestamps(); } public function legalities(): HasMany { return $this->hasMany(UmkmLegality::class); } public function locations(): HasMany { return $this->hasMany(UmkmLocation::class); } public function products(): HasMany { return $this->hasMany(UmkmProduct::class); } public function businessFields(): HasMany { return $this->hasMany(UmkmBusinessField::class); } public function performanceRecords(): HasMany { return $this->hasMany(UmkmPerformanceRecord::class); } public function updateSubmissions(): HasMany { return $this->hasMany(UmkmUpdateSubmission::class); }}

